function renderConfig(){const c=state.config;$('#mode-pill').textContent=c.apply?'Apply enabled':'Dry run';$('#mode-pill').className=`pill ${c.apply?'live':'dry'}`;$('#side-mode').textContent=c.apply?'Apply enabled':'Dry run';$('#side-dot').className=`dot ${c.apply?'warn':'ok'}`;$('#stat-pools').textContent=c.pools.length;$('#routing-head').innerHTML=`<tr><th>Service</th>${c.pools.map(p=>`<th colspan="2" class="pool-heading">${esc(p.name)}</th>`).join('')}</tr><tr class="subhead"><th></th>${c.pools.map(()=>'<th>Category</th><th>Root folder</th>').join('')}</tr>`;const services=[['Radarr','radarr_category','radarr_root'],['Sonarr','sonarr_category','sonarr_root']];$('#pool-rows').innerHTML=services.map(([name,categoryKey,rootKey])=>`<tr><td class="service-name">${esc(name)}</td>${c.pools.map(p=>`<td><span class="category">${esc(p[categoryKey])}</span></td><td class="path">${esc(p[rootKey])}</td>`).join('')}</tr>`).join('');$('#settings-pools').innerHTML=c.pools.map(p=>`<article class="settings-card"><h2>${esc(p.name)}</h2><dl class="settings-grid"><dt>Pool prefix</dt><dd>${esc(p.prefix)}</dd><dt>Download roots</dt><dd>${p.download_roots.map(esc).join('<br>')}</dd><dt>Radarr root / tag</dt><dd>${esc(p.radarr_root)} · ${esc(p.radarr_tag)}</dd><dt>Sonarr root / tag</dt><dd>${esc(p.sonarr_root)} · ${esc(p.sonarr_tag)}</dd><dt>Categories</dt><dd>${esc(p.radarr_category)} · ${esc(p.sonarr_category)}</dd></dl></article>`).join('');$('#move-target').innerHTML=c.pools.map(p=>`<option value="${esc(p.name)}">${esc(p.name)}</option>`).join('')}
function renderConnections(){const services=state.connections?.services;if(!services)return;const form=$('#connections-form');form.elements['qbittorrent-url'].value=services.qbittorrent.url||'';form.elements['qbittorrent-api-key'].placeholder=services.qbittorrent.api_key_set?'Saved API key · preferred authentication':'API key recommended for qBittorrent 5.2+';form.elements['qbittorrent-username'].value=services.qbittorrent.username||'';form.elements['qbittorrent-password'].placeholder=services.qbittorrent.password_set?'Saved password · login fallback':'Password for login fallback';form.elements['radarr-url'].value=services.radarr.url||'';form.elements['radarr-api-key'].placeholder=services.radarr.api_key_set?'Saved API key · leave blank to keep':'API key required when Radarr is configured';form.elements['sonarr-url'].value=services.sonarr.url||'';form.elements['sonarr-api-key'].placeholder=services.sonarr.api_key_set?'Saved API key · leave blank to keep':'API key required when Sonarr is configured';const configured=state.connections.configured||{};const count=Object.values(configured).filter(Boolean).length;const complete=state.connections.status==='ready';$('#connections-status').textContent=complete?'All connected':count?`${count} of 3 connected`:'Not configured';$('#connections-status').className=`badge ${complete?'complete':count?'partial':'blocked'}`;$('#connection-error').textContent=state.connections.error||'';$('#connection-error').classList.toggle('hidden',!state.connections.error);$('#setup-error').textContent=state.connections.error||'';$('#setup-error').classList.toggle('hidden',!state.connections.error);const states={qbit:Boolean(configured.qbittorrent),radarr:Boolean(configured.radarr),sonarr:Boolean(configured.sonarr)};Object.entries(states).forEach(([name,connected])=>{const node=$(`#${name}-connection-state`);node.textContent=connected?'Connected':'Optional';node.className=`badge ${connected?'complete':'partial'}`});const method=services.qbittorrent.api_key_set?'API key':services.qbittorrent.password_set?'Username/password fallback':'Not configured';$('#qbit-auth-summary').textContent=`qBittorrent authentication: ${method}`}
function renderRuntime(){if(!state.runtime)return;$('#runtime-apply').checked=state.runtime.apply;$('#runtime-status').textContent=state.runtime.apply?'Apply enabled':'Dry run';$('#runtime-status').className=`badge ${state.runtime.apply?'complete':'dry_run'}`;const deployment=state.runtime.deployment;$('#deployment-settings').innerHTML=`<div class="deployment-note"><strong>Docker deployment settings</strong><span>These values define the container boundary and require a Compose recreate to change safely.</span></div>${deployment.running_as_root?'<div class="alert inline-alert">The API process is running as root. Configure PUID and PGID or a non-root container user before enabling writes.</div>':''}<dl><dt>Configured identity</dt><dd>${esc(deployment.configured_puid)}:${esc(deployment.configured_pgid)}</dd><dt>Effective identity</dt><dd>${esc(deployment.process_uid)}:${esc(deployment.process_gid)}</dd><dt>File creation umask</dt><dd>${esc(deployment.umask)}</dd><dt>Media mount mode</dt><dd>${esc(deployment.media_mount_mode)}</dd><dt>API token</dt><dd>${deployment.api_token_set?'Configured':'Not configured'}</dd><dt>API listener</dt><dd>${esc(deployment.listen)}:${esc(deployment.port)}</dd><dt>API-only service</dt><dd>${deployment.api_only?'Enabled':'Disabled'}</dd><dt>Timezone</dt><dd>${esc(deployment.timezone)}</dd>${deployment.pool_mounts.map(pool=>`<dt>${esc(pool.name)} mount</dt><dd>${esc(pool.prefix)} · ${pool.writable?'writable':'read-only'}</dd>`).join('')}</dl>`}
function renderSecurity(){const method=state.auth?.method||state.runtime?.deployment?.auth_method||'forms';$('#password-panel').classList.toggle('hidden',method!=='forms');$('#security-summary').innerHTML=`<div><small>Authentication method</small><strong>${esc(method==='external'?'External proxy':'Forms')}</strong></div><div><small>Active sessions</small><strong>${state.sessions.length}</strong></div><div><small>API authentication</small><strong>Bearer or X-Api-Key</strong></div>`;$('#revoke-sessions').disabled=method!=='forms'||!state.sessions.length;$('#security-events').innerHTML=state.securityEvents.length?state.securityEvents.map(item=>`<tr><td>${badge(item.event)}</td><td>${esc(item.username||'—')}</td><td>${esc(item.client||'—')}</td><td>${fmtTime(item.created_at)}</td></tr>`).join(''):'<tr><td colspan="4" class="empty">No security events recorded</td></tr>'}
function renderOperations(){const ops=state.operations;$('#history-count').textContent=ops.length||'';$('#stat-operations').textContent=ops.length;$('#stat-complete').textContent=ops.filter(x=>x.state==='COMPLETE').length;$('#stat-blocked').textContent=ops.filter(x=>['BLOCKED','FAILED'].includes(x.state)).length;$('#recent-list').innerHTML=ops.slice(0,5).map(op=>`<div class="activity">${badge(op.state)}<div><strong>${esc(op.detail?.torrent_name||op.torrent_hash)}</strong><small>${esc(op.kind||'reconcile')} · ${esc(op.app||'unknown')} · ${fmtTime(op.updated_at)}</small></div><button class="link-button inspect-operation" data-operation-id="${op.id}">Details</button></div>`).join('');$('#operation-rows').innerHTML=ops.length?ops.map(op=>`<tr><td>${op.id}</td><td>${badge(op.kind||'reconcile')}</td><td>${esc(op.app||'—')}</td><td>${esc(op.detail?.torrent_name||op.torrent_hash)}</td><td>${badge(op.state)}</td><td>${fmtTime(op.updated_at)}</td><td><button class="link-button inspect-operation" data-operation-id="${op.id}">Details</button></td></tr>`).join(''):`<tr><td colspan="7" class="empty">No operations recorded</td></tr>`}
function renderPlan(plan){
  const error=plan.status==='blocked'?`<div class="alert"><div class="alert-head"><span>✕</span> Reconciliation blocked ${plan.error_code?`<code>${esc(plan.error_code)}</code>`:''}</div><p>${esc(plan.reason)}</p>${plan.error_details?.action?`<p><strong>Action:</strong> ${esc(plan.error_details.action)}</p>`:''}</div>`:'';
  const service=plan.app==='sonarr'?'Sonarr':'Radarr';
  const itemType=plan.app==='sonarr'?'Series':'Movie';
  const details=[['Status',badge(plan.status)],['Application',esc(service)],['Authoritative pool',esc(plan.target_pool||'—')],[`${service} ${itemType.toLowerCase()}`,plan.item_id?`${esc(plan.item_title)} (#${plan.item_id})`:'—'],['Torrent',esc(plan.torrent_name||'—')],[`Current ${service} ${itemType.toLowerCase()} folder`,`<span class="path">${esc(plan.current_item_path||'—')}</span>`],[`New ${service} ${itemType.toLowerCase()} folder`,`<span class="path">${esc(plan.target_item_path||'—')}</span>`],['Torrent hash',`<span class="path">${esc(plan.torrent_hash)}</span>`]];
  const pairs=plan.pairs?.length?plan.pairs.map(p=>{const packed=p.strategy==='archive-reextract'||p.strategy==='verified-copy';const already=p.status==='already-on-target';return `<div class="pair"><div class="pair-summary">${badge(p.status)}${badge(p.strategy)}<strong>${(p.size/1073741824).toFixed(2)} GiB</strong></div><div class="file-flow"><div class="flow-card canonical"><span class="flow-step">1 · SOURCE OF TRUTH / KEEP</span><h3>${packed?'qBittorrent archive set':`qBittorrent download on ${esc(poolForPath(p.torrent_file))}`}</h3><p>${packed?'The archive manifest and save path are authoritative. Extracted files are disposable derived artifacts.':'This save path determines the authoritative pool. The download is kept.'}</p><code class="path">${packed?'Archive content must pass a qBittorrent recheck and extractor test':esc(p.torrent_file)}</code></div><div class="flow-arrow">→</div><div class="flow-card target"><span class="flow-step">2 · ${packed?(already?'KEEP':'RE-EXTRACT'):'CREATE'}</span><h3>${packed?(already?'Imported media already on the authoritative pool':`Regenerate media with Stowarr on ${esc(poolForPath(p.target_library))}`):`New library hardlink on ${esc(poolForPath(p.target_library))}`}</h3><p>${packed?(already?'No media move is required.':'Stowarr extracts the qBittorrent-owned archives into isolated staging and verifies the result before import.'):'Created as a hardlink to the qBittorrent file after verification.'}</p><code class="path">${esc(p.target_library)}</code></div><div class="flow-arrow">→</div><div class="flow-card obsolete"><span class="flow-step">3 · ${already?'CURRENT LIBRARY':'SUSPECTED STALE DERIVATIVE'}</span><h3>${already?'Current imported media':`Old derived media on ${esc(poolForPath(p.source_library))}`}</h3><p>${already?'This file is already on the pool selected by qBittorrent.':'It is removed only after Stowarr has extracted, verified, and imported the media on the authoritative pool.'}</p><code class="path">${esc(p.source_library)}</code></div></div></div>`}).join(''):'<div class="empty">No file pairs available</div>';
  const missingAux=(plan.auxiliary_files||[]).filter(x=>['missing-target','torrent-sidecar'].includes(x.status));
  const conflicts=(plan.auxiliary_files||[]).filter(x=>['target-conflict','torrent-name-conflict'].includes(x.status));
  const eligibleAux=(plan.auxiliary_files||[]).filter(x=>!['target-conflict','torrent-name-conflict'].includes(x.status));
  const auxiliary=plan.auxiliary_files?.length?`<div class="auxiliary"><label class="check-option select-all"><input id="select-all-auxiliary" type="checkbox" ${eligibleAux.length?'checked':'disabled'}><span><strong>Select all ${eligibleAux.length} eligible sidecar files</strong><small>qBittorrent-owned files are hardlinked. Files found only in the old library are copied and verified.</small></span></label><details open><summary>Sidecar files · ${missingAux.length} missing at destination${conflicts.length?` · ${conflicts.length} conflict`:''}</summary><div class="aux-list">${plan.auxiliary_files.map(x=>{const selectable=!['target-conflict','torrent-name-conflict'].includes(x.status);const origin=x.origin==='qbittorrent'?'qBittorrent · hardlink':'Old library · copy';return `<label class="aux-row ${selectable?'':'disabled'}"><input class="aux-file" type="checkbox" data-source="${esc(x.source)}" ${selectable?'checked':'disabled'}><span class="origin">${esc(origin)}</span><span>${badge(x.status)}</span><code class="path">${esc(x.source)}</code><span>→</span><code class="path">${esc(x.target)}</code></label>`}).join('')}</div></details>${conflicts.length?`<div class="aux-warning">${conflicts.length} file(s) compete for the same destination or differ from an existing target. They are disabled and will not be overwritten automatically.</div>`:''}</div>`:'';
  const ready=plan.status==='ready';
  const apply=Boolean(state.config?.apply);
  const action=ready?`<div id="verification-result"></div><div class="reconcile-action"><div><strong>${apply?'Ready for verified reconciliation':'Deletion is locked in dry-run mode'}</strong><p>${apply?'Stowarr will hash-verify, create the new hardlink, update *Arr, and only then remove the verified duplicate.':'Set STOWARR_APPLY=true and provide writable media mounts only after reviewing the plan.'}</p></div><div class="action-buttons"><button id="verify-plan" class="secondary">Verify content hashes</button><button id="apply-plan" class="danger" ${apply?'':'disabled'}>Reconcile &amp; remove verified duplicate</button></div></div>`:'';
  $('#plan-result').innerHTML=`${error}<article class="panel"><div class="panel-head"><div><h2>Plan details</h2><p>No changes have been made</p></div></div><div class="detail-grid">${details.map(([k,v])=>`<div class="detail"><small>${k}</small><strong>${v}</strong></div>`).join('')}</div></article><article class="panel"><div class="panel-head"><div><h2>File migration and hardlinks</h2><p>qBittorrent determines the authoritative pool; suspected duplicates are removed only after verification</p></div></div>${pairs}${auxiliary}${action}</article>`
}
async function applyPlan(){const plan=state.plan;if(!plan||plan.status!=='ready'||!state.config?.apply)return;const oldFiles=plan.pairs.map(p=>p.source_library).join(', ');const auxiliaryFiles=$$('.aux-file:checked').map(input=>input.dataset.source);if(!await confirmAction({title:`Reconcile ${plan.item_title}?`,message:'Suspected duplicates are removed only after content verification.',details:[['Suspected duplicates',oldFiles],['Selected sidecar files',String(auxiliaryFiles.length)]],confirmLabel:'Reconcile',danger:true}))return;const button=$('#apply-plan');button.disabled=true;button.textContent='Authorizing…';try{const confirmation=await api('/api/confirmations',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({kind:'reconcile',torrentHash:plan.torrent_hash,payload:{auxiliaryFiles}})});button.textContent='Reconciling…';const result=await api(`/api/reconcile/${encodeURIComponent(plan.torrent_hash)}`,{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({auxiliaryFiles,confirmationToken:confirmation.token})});toast(`Reconcile result: ${result.state}`);await inspect(plan.torrent_hash);await load()}catch(e){toast(`Reconcile failed: ${e.message}`);button.disabled=false;button.textContent='Reconcile & remove verified duplicate'}}
function renderSubtitleInventory(plan){const subtitles=plan.subtitle_files||[];if(!subtitles.length)return '<div class="move-no-extras">No subtitles were found in the torrent folders or archive manifests.</div>';const archiveCount=subtitles.filter(file=>file.location==='archive').length;const subfolderCount=subtitles.filter(file=>file.location==='subfolder').length;const torrentCount=subtitles.filter(file=>file.location==='torrent').length;return `<details class="move-manifest subtitle-inventory"><summary><strong>Subtitle discovery</strong><span>${subtitles.length} found · ${archiveCount} in archives · ${subfolderCount} in subfolders · ${torrentCount} beside media</span></summary><div class="table-wrap"><table><thead><tr><th>Location</th><th>Subtitle path</th><th>Archive source</th></tr></thead><tbody>${subtitles.map(file=>`<tr><td>${badge(file.location)}</td><td class="path">${esc(file.path)}</td><td class="path">${esc(file.archive||'—')}</td></tr>`).join('')}</tbody></table></div></details>`}
function renderMoveBlocker(plan){if(plan.status!=='blocked')return '';if(plan.error_code==='LIBRARY_SEEDED_MAPPING_REQUIRED'){const details=plan.error_details||{};const service=plan.app==='sonarr'?'Sonarr':'Radarr';return `<article class="panel release-conflict"><div class="panel-head"><div><h2>No exact ${service} media match</h2><p>The torrent is safely left untouched. Its files are already inside the ${service} library, but ${service} does not currently report these exact paths as managed media.</p></div>${badge('blocked')}</div><div class="release-evidence"><div><small>qBittorrent torrent</small><strong>${esc(details.torrent_name||plan.torrent_name)}</strong><code>${esc(details.torrent_hash||plan.torrent_hash)}</code></div><div><small>qBittorrent content path${(details.media_paths||[]).length===1?'':'s'}</small>${(details.media_paths||[]).map(path=>`<code>${esc(path)}</code>`).join('')||`<code>${esc(details.save_path||'Unknown')}</code>`}</div></div><div class="recovery-guidance"><div><strong>How to resolve this</strong><p>${esc(details.action||`Verify the current media file in ${service}, then build the Move plan again.`)}</p></div><button type="button" class="secondary" id="recheck-release-identity">Build plan again</button></div></article>`}if(plan.error_code!=='ARR_CURRENT_RELEASE_MISMATCH')return `<div class="alert"><div class="alert-head"><span>✕</span> Move blocked</div><p>${esc(plan.reason)}</p>${plan.error_details?.action?`<p><strong>How to resolve this:</strong> ${esc(plan.error_details.action)}</p><button type="button" class="secondary" id="recheck-release-identity">Build plan again</button>`:''}</div>`;const details=plan.error_details||{};const files=details.files||[];return `<article class="panel release-conflict"><div class="panel-head"><div><h2>Release identity conflict</h2><p>Stowarr stopped before changing qBittorrent, files, or *Arr.</p></div>${badge('blocked')}</div><div class="release-evidence"><div><small>Selected qBittorrent release</small><strong>${esc(details.torrent_name||plan.torrent_name)}</strong><code>${esc(details.torrent_hash||plan.torrent_hash)}</code></div><div><small>Current ${plan.app==='sonarr'?'Sonarr':'Radarr'} item</small><strong>${esc(details.arr_item_title||plan.item_title||'Unknown')} ${details.arr_item_id?`(#${esc(details.arr_item_id)})`:''}</strong><span>The item matches, but its current media release does not.</span></div></div><div class="table-wrap"><table><thead><tr><th>Current *Arr media file</th><th>Matching torrent file</th><th>Result</th></tr></thead><tbody>${files.map(file=>`<tr><td class="path">${esc(file.arr_file)}</td><td class="path">${esc(file.torrent_file||`${file.candidate_count||0} same-size candidate(s), none verified`)}</td><td>${badge(file.status)}</td></tr>`).join('')}</tbody></table></div><div class="recovery-guidance"><div><strong>Safe recovery</strong><p>${esc(details.action||'Import the intended release in *Arr, then check again.')}</p></div><button type="button" class="secondary" id="recheck-release-identity">Recheck release identity</button></div></article>`}
function renderMovePlan(plan){const blocked=renderMoveBlocker(plan);const service=plan.app==='sonarr'?'Sonarr':'Radarr';const itemType=plan.app==='sonarr'?'series':'movie';const extractionIds=new Set((plan.extraction_files||[]).map(file=>file.id));const files=plan.managed_files?.length?`<div class="table-wrap"><table><thead><tr><th>${service} file ID</th><th>Episodes</th><th>Current library file</th><th>New library file</th><th>Strategy</th><th>Size</th></tr></thead><tbody>${plan.managed_files.map(file=>`<tr><td>${esc(file.id??'—')}</td><td>${file.episodeIds?.length?file.episodeIds.map(id=>`#${esc(id)}`).join(', '):'—'}</td><td class="path">${esc(file.path)}</td><td class="path">${esc(file.targetPath)}</td><td>${extractionIds.has(file.id)?badge('verified re-extraction'):badge('hardlink')}</td><td>${fmtBytes(file.size)}</td></tr>`).join('')}</tbody></table></div>`:'<div class="empty">No managed library files were mapped</div>';const tracked=plan.tracked_files?.length?`<details class="move-manifest"><summary><strong>qBittorrent-owned content</strong><span>${plan.tracked_files.length} tracked files · ${fmtBytes(plan.tracked_files.reduce((sum,file)=>sum+file.size,0))}</span></summary><div class="table-wrap"><table><thead><tr><th>Type</th><th>Relative torrent path</th><th>Size</th><th>Action</th></tr></thead><tbody>${plan.tracked_files.map(file=>`<tr><td>${badge(file.kind)}</td><td class="path">${esc(file.relative_path)}</td><td>${fmtBytes(file.size)}</td><td>Move with qBittorrent and recheck</td></tr>`).join('')}</tbody></table></div></details>`:'';const extras=plan.additional_files?.length?`<section class="move-extras"><div class="move-extras-head"><div><h3>Additional files</h3><p>Every untracked download or library file requires an explicit action. Files are removed only after all verification completes.</p></div><div><button type="button" class="secondary compact set-extra-action" data-action="move">Move all</button><button type="button" class="secondary compact set-extra-action" data-action="delete">Delete all</button></div></div><div class="table-wrap"><table><thead><tr><th>Scope</th><th>Type</th><th>Current file</th><th>Destination</th><th>Size</th><th>After verification</th></tr></thead><tbody>${plan.additional_files.map(file=>`<tr><td>${badge(file.scope)}</td><td>${badge(file.kind)}</td><td class="path">${esc(file.source)}</td><td class="path">${esc(file.target)}</td><td>${fmtBytes(file.size)}</td><td><select class="move-extra-action" data-source="${esc(file.source)}"><option value="move" selected>Move and verify</option><option value="delete">Delete after verification</option></select></td></tr>`).join('')}</tbody></table></div></section>`:'<div class="move-no-extras">No additional files were found outside qBittorrent and *Arr ownership.</div>';const apply=Boolean(state.config?.apply);const action=plan.status==='ready'?`<div class="reconcile-action"><div><strong>${apply?'Ready for a verified Move transaction':'Move is locked in dry-run mode'}</strong><p>qBittorrent moves and rechecks tracked content first. ${plan.extraction_required?'Stowarr then tests and re-extracts archive-derived media in isolated staging. ':''}Stowarr verifies additional files, rebuilds the ${itemType} library, waits for the ${service} rescan, and removes the empty old folder last.</p></div><button id="apply-move" class="danger" ${apply?'':'disabled'}>Review &amp; move to ${esc(plan.target_pool)}</button></div>`:'';$('#move-result').innerHTML=`${blocked}<article class="panel"><div class="panel-head"><div><h2>Move plan</h2><p>No changes have been made</p></div></div><div class="detail-grid"><div class="detail"><small>Status</small><strong>${badge(plan.status)}</strong></div><div class="detail"><small>${service} ${itemType}</small><strong>${esc(plan.item_title||'—')}${plan.item_id?` (#${esc(plan.item_id)})`:''}</strong></div><div class="detail"><small>Current authoritative pool</small><strong>${esc(plan.current_pool||'—')}</strong></div><div class="detail"><small>Selected destination pool</small><strong>${esc(plan.target_pool)}</strong></div><div class="detail"><small>Current qBittorrent save path</small><strong class="path">${esc(plan.current_save_path||'—')}</strong></div><div class="detail"><small>New qBittorrent save path</small><strong class="path">${esc(plan.target_save_path||'—')}</strong></div><div class="detail"><small>New qBittorrent category</small><strong>${esc(plan.target_category||'—')}</strong></div><div class="detail"><small>Content</small><strong>${badge(plan.content_mode)} ${plan.archive_files?`· ${esc(plan.archive_files)} archive files · ${plan.archive_verified?'integrity verified':'verification required'}`:''}</strong></div><div class="detail"><small>Required / available space</small><strong>${fmtBytes(plan.torrent_size+(plan.extraction_space||0))} / ${plan.free_space===null?'unknown':fmtBytes(plan.free_space)}</strong><span>${plan.extraction_space?`${fmtBytes(plan.extraction_space)} reserved for verified extraction`:''}</span></div></div></article><article class="panel"><div class="panel-head"><div><h2>Move manifest</h2><p>Complete inventory from qBittorrent, ${service}, the download folder, and the library folder</p></div></div>${tracked}${renderSubtitleInventory(plan)}<div class="managed-section"><h3>Managed library files</h3><p>Resolved from the torrent hash and ${service} history</p></div>${files}${extras}${action}</article>`}
function initializeMoveActions(plan){(plan.additional_files||[]).filter(file=>file.status==='target-conflict').forEach(file=>{const input=$(`.move-extra-action[data-source="${CSS.escape(file.source)}"]`);if(!input)return;input.value='delete';input.options[0].disabled=true;input.title='The destination already contains different data. Resolve it manually or delete this source after verification.'})}
async function inspectMove(hash,targetPool){navigate('move');$('#move-hash').value=hash;$('#move-target').value=targetPool;$('#move-loading').classList.remove('hidden');$('#move-result').innerHTML='';try{state.movePlan=await api(`/api/move/plan/${encodeURIComponent(hash)}?targetPool=${encodeURIComponent(targetPool)}`);renderMovePlan(state.movePlan);initializeMoveActions(state.movePlan)}catch(e){$('#move-result').innerHTML=`<div class="alert"><div class="alert-head">Request failed</div><p>${esc(e.message)}</p></div>`}finally{$('#move-loading').classList.add('hidden')}}
async function applyMove(){const plan=state.movePlan;if(!plan||plan.status!=='ready'||!state.config?.apply)return;const additionalFiles=Object.fromEntries($$('.move-extra-action').map(input=>[input.dataset.source,input.value]));const moving=Object.values(additionalFiles).filter(action=>action==='move').length;const deleting=Object.values(additionalFiles).filter(action=>action==='delete').length;if(!await confirmAction({title:`Move ${plan.torrent_name}?`,message:'Review the complete transaction. The torrent is isolated from *Arr cleanup until every verification and library update succeeds.',details:[['Pool route',`${plan.current_pool} → ${plan.target_pool}`],['1 · Pause and isolate','Temporary Stowarr category on the destination pool'],['2 · Relocate and recheck',`${plan.tracked_files?.length||0} qBittorrent-owned files`],['3 · Rebuild library',`${plan.managed_files?.length||0} managed files and ${moving} additional files`],['4 · Delete after verification',`${deleting} explicitly selected files`],['5 · Commit final route',plan.target_category||'No category']],confirmLabel:`Confirm move to ${plan.target_pool}`,danger:true}))return;const button=$('#apply-move');button.disabled=true;button.textContent='Authorizing…';const payload={targetPool:plan.target_pool,additionalFiles};const afterId=Math.max(0,...state.operations.map(item=>item.id));try{const confirmation=await api('/api/confirmations',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({kind:'move',torrentHash:plan.torrent_hash,payload})});button.textContent='Moving and verifying…';trackOperation(plan.torrent_hash,'move',afterId);const result=await api(`/api/move/apply/${encodeURIComponent(plan.torrent_hash)}`,{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({...payload,confirmationToken:confirmation.token})});await refreshOperations();toast(`Move result: ${result.state}`);clearMoveSelection();state.qbitCatalog=null;await loadQbitCatalog(true);await load()}catch(e){await refreshOperations();toast(`Move failed: ${e.message}`);button.disabled=false;button.textContent=`Review & move to ${plan.target_pool}`}}
function catalogRows(){if(!state.qbitCatalog)return [];return [...state.qbitCatalog.routes,...(state.qbitCatalog.library_seeded||[]),...state.qbitCatalog.unmanaged].flatMap(group=>group.paths.flatMap(path=>path.torrents))}
function torrentCard(row){return `<button class="torrent-card select-move ${esc(row.route_status)}" data-hash="${esc(row.hash)}" type="button"><strong>${esc(row.name)}</strong><span><i>${esc(row.category||'uncategorized')}</i>${badge(row.route_status)}${badge(row.state)}</span><small>${fmtBytes(row.size)} · ${(row.progress*100).toFixed(1)}%</small><code>${esc(row.hash)}</code></button>`}
function renderCatalogPaths(paths,terms,primary){return paths.map(path=>{const torrents=path.torrents.filter(row=>{if(!terms.length)return true;const searchable=[row.name,row.hash,row.category,row.save_path,path.path].map(value=>String(value||'').toLowerCase()).join(' ');return terms.every(term=>searchable.includes(term))});if(!torrents.length)return {html:'',count:0};const expanded=terms.length>0||primary||path.route==='download';return {count:torrents.length,html:`<details class="path-group ${esc(path.route||'route')}" ${expanded?'open':''}><summary><span><em>${esc(path.route||'actual path')}</em>${esc(path.path)}</span><b>${torrents.length}</b></summary><div class="torrent-cards">${torrents.map(torrentCard).join('')}</div></details>`}})}
function renderQbitCatalog(){if(!state.qbitCatalog)return;const terms=$('#move-search').value.trim().toLowerCase().split(/\s+/).filter(Boolean);const routeGroups=state.qbitCatalog.routes.map((route,index)=>({kind:'route',key:`route:${route.app}:${route.pool}:${route.category}:${index}`,label:`${route.app[0].toUpperCase()+route.app.slice(1)} · ${route.pool}`,group:route}));const libraryGroups=(state.qbitCatalog.library_seeded||[]).map((group,index)=>({kind:'library',key:`library:${group.app}:${group.pool}:${index}`,label:`Library-seeded · ${group.app[0].toUpperCase()+group.app.slice(1)} · ${group.pool}`,group}));const unmanagedGroups=state.qbitCatalog.unmanaged.map((group,index)=>({kind:'unmanaged',key:`unmanaged:${group.pool||'outside'}:${index}`,label:`Unmanaged · ${group.pool||'outside pools'}`,group}));const columns=[...routeGroups,...libraryGroups,...unmanagedGroups];const availableKeys=new Set(columns.map(column=>column.key));state.hiddenMoveColumns.forEach(key=>{if(!availableKeys.has(key))state.hiddenMoveColumns.delete(key)});const shown=columns.filter(column=>!state.hiddenMoveColumns.has(column.key));$('#move-column-filters').innerHTML=`<span>Columns</span><div>${columns.map(column=>`<button type="button" class="column-toggle ${state.hiddenMoveColumns.has(column.key)?'':'active'}" data-column-key="${esc(column.key)}" aria-pressed="${state.hiddenMoveColumns.has(column.key)?'false':'true'}"><i></i>${esc(column.label)}<b>${column.group.count}</b></button>`).join('')}</div><button type="button" id="show-all-columns" class="text-button" ${state.hiddenMoveColumns.size?'':'disabled'}>Show all</button>`;let visible=0;const renderedColumns=shown.map(column=>{const primary=column.kind==='route';const rendered=renderCatalogPaths(column.group.paths,terms,primary);visible+=rendered.reduce((sum,item)=>sum+item.count,0);if(primary){const route=column.group;return `<section class="pool-column route-column" data-column="${esc(column.key)}"><header><div><h3>${esc(column.label)}</h3><small>${esc(route.category)} · ${esc(route.tag)}</small><code>${esc(route.root)}</code></div><strong>${route.count}</strong></header><div class="pool-column-body">${rendered.map(item=>item.html).join('')||'<div class="empty">No matching routed torrents</div>'}</div></section>`}const group=column.group;if(column.kind==='library')return `<section class="pool-column library-column" data-column="${esc(column.key)}"><header><div><h3>${esc(column.label)}</h3><small>qBittorrent is seeding directly from the managed library</small><code>${esc(group.root)}</code></div><strong>${group.count}</strong></header><div class="pool-column-body">${rendered.map(item=>item.html).join('')||'<div class="empty">No matching library-seeded torrents</div>'}</div></section>`;return `<section class="pool-column unmanaged-column" data-column="${esc(column.key)}"><header><div><h3>${esc(column.label)}</h3><small>Category does not match a configured *Arr route</small></div><strong>${group.count}</strong></header><div class="pool-column-body">${rendered.map(item=>item.html).join('')||'<div class="empty">No matching unmanaged torrents</div>'}</div></section>`}).join('');$('#move-visible-count').textContent=`${visible} visible · ${state.qbitCatalog.total} total`;$('#move-search-results').innerHTML=shown.length?`<div class="pool-board">${renderedColumns}</div>`:'<div class="empty column-empty">All torrent columns are hidden. Use the column filter to show one or more.</div>'}
function renderRoutingAudit(){if(!state.routingAudit)return;const audit=state.routingAudit;$('#move-routing-status').innerHTML=`<div class="routing-status ${esc(audit.status)}"><div>${badge(audit.status)}<span>${audit.status==='ready'?'All configured *Arr category routes are complete':`${audit.issue_count} routing issue(s) need attention`}</span></div><button id="open-routing-guide" class="secondary">Routing diagnostics</button></div>`;const routes=audit.services.flatMap(service=>service.routes);$('#routing-guide-content').innerHTML=routes.map(route=>`<article class="guide-route ${esc(route.status)}"><header><div><h3>${esc(route.app[0].toUpperCase()+route.app.slice(1))} · ${esc(route.pool)}</h3><span>${badge(route.status)}</span></div><code>${esc(route.category)}</code></header><div class="guide-chain"><div><small>1 · *ARR DOWNLOAD CLIENT</small><strong>${esc(route.download_clients[0]?.name||'Missing')}</strong></div><b>→</b><div><small>2 · ROUTE CATEGORY</small><strong>${esc(route.category)}</strong></div><b>→</b><div><small>3 · QBITTORRENT SAVE PATH</small><strong>${esc(route.qbit_save_path||'missing')}</strong></div></div><div class="guide-guards"><div><small>CLIENT SELECTION TAG</small><strong>${esc(route.tag)}</strong><span>${route.download_clients[0]?.tags.includes(route.tag)?'Attached to this client':'Not attached to this client'}</span></div><div><small>LIBRARY DESTINATION</small><strong>${esc(route.root)}</strong><span>Root folder for the selected movie or series</span></div></div>${route.issues.length?`<ul>${route.issues.map(issue=>`<li>${esc(issue)}</li>`).join('')}</ul>`:'<p class="route-ready">Category route and client restriction are complete.</p>'}</article>`).join('')}
function clearMoveSelection(){state.moveTorrent=null;state.movePlan=null;$('#move-hash').value='';$('#move-selected-name').textContent='';$('#move-selected-hash').textContent='';$('.move-selection').classList.add('hidden');$('#move-result').innerHTML=''}
async function loadQbitCatalog(force=false){if(state.qbitCatalog&&state.routingAudit&&!force){renderRoutingAudit();renderQbitCatalog();return}clearMoveSelection();$('#move-search-loading').classList.remove('hidden');$('#move-search-results').innerHTML='';try{const [catalog,audit]=await Promise.all([api('/api/qbittorrent/torrents'),api('/api/routing/audit')]);state.qbitCatalog=catalog;state.routingAudit=audit;renderRoutingAudit();renderQbitCatalog()}catch(e){$('#move-search-results').innerHTML=`<div class="alert inline-alert"><div class="alert-head">qBittorrent catalog failed</div><p>${esc(e.message)}</p></div>`}finally{$('#move-search-loading').classList.add('hidden')}}
function selectMoveTorrent(hash){const torrent=catalogRows().find(row=>row.hash===hash);if(!torrent)return;state.moveTorrent=torrent;$('#move-hash').value=hash;$('#move-selected-name').textContent=torrent.name;$('#move-selected-hash').textContent=hash;$('.move-selection').classList.remove('hidden');const destination=state.config.pools.find(pool=>pool.name!==torrent.pool)||state.config.pools[0];if(destination)$('#move-target').value=destination.name;$('#move-result').innerHTML='';$('.move-selection').scrollIntoView({behavior:'smooth',block:'nearest'})}
function hashCell(file,label){if(!file)return `<div><small>${esc(label)}</small><strong>Not applicable</strong><span>Packed torrent: media is not part of the torrent manifest</span></div>`;if(!file.exists)return `<div><small>${esc(label)}</small><strong>Not present</strong><code class="path">${esc(file.path)}</code></div>`;return `<div><small>${esc(label)}</small><strong title="${esc(file.sha256)}">SHA-256 ${esc(file.sha256.slice(0,16))}…</strong><span>inode ${file.inode} · links ${file.links}</span><code class="path">${esc(file.path)}</code></div>`}
async function verifyPlan(){const plan=state.plan;if(!plan||plan.status!=='ready')return;const button=$('#verify-plan');button.disabled=true;button.textContent='Hashing files…';$('#verification-result').innerHTML='<div class="loading"><span></span>Hashing torrent, old library, and new library paths. This may take several minutes…</div>';try{const result=await api(`/api/verify/${encodeURIComponent(plan.torrent_hash)}`,{method:'POST'});const videos=result.video_files.map(file=>{const packed=file.strategy==='archive-reextract'||file.strategy==='verified-copy';const valid=packed?file.new_matches_torrent!==false:file.old_matches_torrent&&file.new_matches_torrent!==false;return `<div class="verification-file"><div class="verification-head">${badge(valid?'verified':'mismatch')}<strong>${packed?'Extracted media comparison':'Direct torrent media comparison'}</strong></div><div class="hash-grid">${hashCell(file.torrent,'qBittorrent media file')}${hashCell(file.old_library,'Old library path')}${hashCell(file.new_library,'New library path')}</div><p>${packed?'The archive set remains authoritative; extracted media is verified independently.':`Old matches torrent: ${file.old_matches_torrent?'Yes':'No'}`} · New matches expected content: <b>${file.new_matches_torrent===null?'Not present yet':file.new_matches_torrent?'Yes':'No'}</b></p></div>`}).join('');const sidecarMatched=result.sidecar_files.filter(x=>x.matches_target===true).length;const sidecarMissing=result.sidecar_files.filter(x=>x.matches_target===null).length;const sidecarDifferent=result.sidecar_files.filter(x=>x.matches_target===false).length;$('#verification-result').innerHTML=`<div class="verification ${result.status}"><div class="verification-title"><strong>Hash verification: ${esc(result.status)}</strong><span>${result.sidecar_files.length} sidecars · ${sidecarMatched} matching · ${sidecarMissing} destination missing · ${sidecarDifferent} different</span></div>${videos}</div>`}catch(e){$('#verification-result').innerHTML=`<div class="alert"><div class="alert-head">Hash verification failed</div><p>${esc(e.message)}</p></div>`}finally{button.disabled=false;button.textContent='Verify content hashes'}}
function setSyncApp(app){state.syncApp=app;$$('.service-tab').forEach(x=>x.classList.toggle('active',x.dataset.app===app));$('#sync-title').textContent=`${app[0].toUpperCase()+app.slice(1)} hash audit`;const cached=state.sync[app];if(cached)renderSync(cached);else{$('#sync-summary').innerHTML='';$('#sync-rows').innerHTML=`<tr><td colspan="7" class="empty">Run the ${esc(app[0].toUpperCase()+app.slice(1))} audit to compare hashes</td></tr>`}}
function renderSync(result){const missingLabel=result.app==='sonarr'?'No matching Sonarr series':'No matching Radarr movie';$('#sync-summary').innerHTML=`<span><strong>${result.scanned}</strong><small>qBit torrents</small></span><span><strong>${result.matched_history}</strong><small>hash matches</small></span><span><strong>${result.in_sync}</strong><small>in sync</small></span><span><strong>${result.issues}</strong><small>issues</small></span>`;$('#sync-rows').innerHTML=result.rows.length?result.rows.map(row=>`<tr title="${esc(row.reason)}"><td>${badge(row.status)}</td><td class="sync-title-cell"><strong>${esc(row.torrent_name)}</strong><small>${esc(row.item_title||missingLabel)}</small></td><td><span class="hash-short" title="${esc(row.hash)}">${esc(row.hash.slice(0,12))}…</span></td><td><span class="category">${esc(row.category||'none')}</span></td><td>${esc(row.qbit_pool||'—')}</td><td class="path">${esc(row.arr_path||row.reason)}</td><td><button class="link-button inspect" data-hash="${esc(row.hash)}">Reconcile</button></td></tr>`).join(''):`<tr><td colspan="7" class="empty">No ${esc(result.app)} torrents found in qBittorrent</td></tr>`}
async function runSync(){const app=state.syncApp;$('#sync-loading').classList.remove('hidden');$('#run-sync').disabled=true;try{const result=await api(`/api/sync/${app}`);state.sync[app]=result;renderSync(result)}catch(e){toast(`Audit failed: ${e.message}`)}finally{$(`#sync-loading`).classList.add('hidden');$('#run-sync').disabled=false}}
async function inspect(hash){navigate('reconcile');$('#torrent-hash').value=hash;$('#global-hash').value=hash;$('#plan-loading').classList.remove('hidden');$('#plan-result').innerHTML='';try{state.plan=await api(`/api/plan/${encodeURIComponent(hash.trim())}`);renderPlan(state.plan)}catch(e){$('#plan-result').innerHTML=`<div class="alert"><div class="alert-head">Request failed</div><p>${esc(e.message)}</p></div>`}finally{$('#plan-loading').classList.add('hidden')}}
async function load(){try{const [config,connections,runtime,operations,security,sessions]=await Promise.all([api('/api/config'),api('/api/settings/connections'),api('/api/settings/runtime'),api('/api/operations'),api('/api/security/events'),api('/api/auth/sessions')]);state.config=config;state.connections=connections;state.runtime=runtime;state.operations=operations;state.securityEvents=security.events;state.sessions=sessions.sessions;renderConfig();renderConnections();renderRuntime();renderOperations();renderSecurity()}catch(e){toast(`Could not load Stowarr: ${e.message}`)}}
async function revokeSessions(){if(!await confirmAction({title:'Sign out all sessions?',message:'Every active WebUI session, including this one, will be revoked.',confirmLabel:'Sign out all',danger:true}))return;try{await api('/api/auth/sessions/revoke',{method:'POST'});state.authenticated=false;state.config=null;showLogin('All WebUI sessions were signed out.')}catch(e){toast(`Sessions were not revoked: ${e.message}`)}}
async function saveRuntime(event){event.preventDefault();const apply=$('#runtime-apply').checked;if(!await confirmAction({title:`${apply?'Enable':'Disable'} confirmed write operations?`,message:'Move and Reconcile still require an explicit plan-bound confirmation.',details:[['Execution mode',apply?'Apply enabled':'Dry run']],confirmLabel:apply?'Enable writes':'Enable dry run',danger:apply}))return;const button=event.currentTarget.querySelector('button');button.disabled=true;button.textContent='Validating mounts…';try{state.runtime=await api('/api/settings/runtime',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({apply})});state.config.apply=state.runtime.apply;renderRuntime();renderConfig();toast(`Execution mode: ${apply?'Apply enabled':'Dry run'}`)}catch(e){$('#runtime-apply').checked=state.runtime.apply;toast(`Execution mode was not changed: ${e.message}`)}finally{button.disabled=false;button.textContent='Save execution mode'}}
async function saveConnections(event){event.preventDefault();const form=event.currentTarget;const button=$('#save-connections');const services={qbittorrent:{url:form.elements['qbittorrent-url'].value.trim(),api_key:form.elements['qbittorrent-api-key'].value.trim(),username:form.elements['qbittorrent-username'].value.trim(),password:form.elements['qbittorrent-password'].value},radarr:{url:form.elements['radarr-url'].value.trim(),api_key:form.elements['radarr-api-key'].value.trim()},sonarr:{url:form.elements['sonarr-url'].value.trim(),api_key:form.elements['sonarr-api-key'].value.trim()}};const selected=Object.entries(services).filter(([,service])=>service.url);if(!selected.length){$('#setup-error').textContent='Enter the URL and credentials for at least one service';$('#setup-error').classList.remove('hidden');return}if(!await confirmAction({title:'Test and save configured services?',message:'Existing credentials are kept for blank secret fields. Only services with a URL are tested.',details:selected.map(([name,service])=>[name==='qbittorrent'?'qBittorrent':name[0].toUpperCase()+name.slice(1),service.url]),confirmLabel:'Test and save'}))return;button.disabled=true;button.textContent='Testing connections…';$('#setup-error').classList.add('hidden');try{const result=await api('/api/settings/connections',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({services})});state.connections=result;renderConnections();form.elements['qbittorrent-api-key'].value='';form.elements['qbittorrent-password'].value='';form.elements['radarr-api-key'].value='';form.elements['sonarr-api-key'].value='';state.qbitCatalog=null;state.routingAudit=null;$('#connection-setup').close();toast(`${selected.length} configured service${selected.length===1?'':'s'} tested and saved`)}catch(e){$('#setup-error').textContent=e.message;$('#setup-error').classList.remove('hidden')}finally{button.disabled=false;button.textContent='Test and save configured services'}}
async function discoverRouting(){const button=$('#discover-routing');button.disabled=true;button.textContent='Discovering…';const target=$('#discovery-result');target.className='loading';target.innerHTML='<span></span>Reading qBittorrent first, then Radarr and Sonarr…';try{const result=await api('/api/settings/discovery');const clients=result.services.flatMap(service=>service.download_clients.map(client=>({...client,app:service.app})));target.className='discovery-grid';target.innerHTML=`<section><header><h3>1 · qBittorrent destinations</h3><span>${result.qbit_categories.length} categories</span></header>${result.qbit_categories.map(item=>`<div class="discovery-row"><strong>${esc(item.category)}</strong><code>${esc(item.save_path||'Default save path')}</code></div>`).join('')||'<div class="empty">No qBittorrent categories found</div>'}</section><section><header><h3>2 · *Arr category senders</h3><span>${clients.length} download clients</span></header>${clients.map(item=>`<div class="discovery-row"><strong>${esc(item.app[0].toUpperCase()+item.app.slice(1))} · ${esc(item.name)}</strong><code>${esc(item.category)}</code><small>Tags: ${item.tags.length?item.tags.map(esc).join(', '):'none'}</small></div>`).join('')||'<div class="empty">No categorized *Arr download clients found</div>'}</section><section><header><h3>3 · Library destinations</h3></header>${result.services.flatMap(service=>service.root_folders.map(path=>`<div class="discovery-row"><strong>${esc(service.app[0].toUpperCase()+service.app.slice(1))}</strong><code>${esc(path)}</code></div>`)).join('')}</section>`}catch(e){target.className='alert inline-alert';target.textContent=e.message}finally{button.disabled=false;button.textContent='Discover routes'}}
function updateAuxiliarySelection(){const selectAll=$('#select-all-auxiliary');if(!selectAll)return;const files=$$('.aux-file:not(:disabled)');const selected=files.filter(input=>input.checked).length;selectAll.checked=selected===files.length;selectAll.indeterminate=selected>0&&selected<files.length}
document.addEventListener('click',e=>{const nav=e.target.closest('[data-page]');if(nav)navigate(nav.dataset.page);const go=e.target.closest('[data-go]');if(go)navigate(go.dataset.go);const tab=e.target.closest('.service-tab');if(tab)setSyncApp(tab.dataset.app);const inspectButton=e.target.closest('.inspect');if(inspectButton)inspect(inspectButton.dataset.hash);const moveButton=e.target.closest('.select-move');if(moveButton)selectMoveTorrent(moveButton.dataset.hash);const columnButton=e.target.closest('.column-toggle');if(columnButton){const key=columnButton.dataset.columnKey;if(state.hiddenMoveColumns.has(key))state.hiddenMoveColumns.delete(key);else state.hiddenMoveColumns.add(key);renderQbitCatalog()}if(e.target.closest('#show-all-columns')){state.hiddenMoveColumns.clear();renderQbitCatalog()}const bulkAction=e.target.closest('.set-extra-action');if(bulkAction)$$('.move-extra-action').forEach(input=>input.value=bulkAction.dataset.action);if(e.target.closest('#verify-plan'))verifyPlan();if(e.target.closest('#apply-plan'))applyPlan();if(e.target.closest('#apply-move'))applyMove();if(e.target.closest('#recheck-release-identity')&&state.movePlan)inspectMove(state.movePlan.torrent_hash,state.movePlan.target_pool);if(e.target.closest('#refresh-qbit'))loadQbitCatalog(true);if(e.target.closest('#discover-routing'))discoverRouting();if(e.target.closest('#open-routing-guide'))$('#routing-guide').showModal();if(e.target.closest('#close-routing-guide'))$('#routing-guide').close();if(e.target.closest('#open-connection-setup'))$('#connection-setup').showModal();if(e.target.closest('#close-connection-setup'))$('#connection-setup').close()});$('#login-dialog').addEventListener('cancel',e=>e.preventDefault());$('#login-form').addEventListener('submit',login);$('#logout').addEventListener('click',logout);$('#password-form').addEventListener('submit',changePassword);$('#run-sync').addEventListener('click',runSync);$('#plan-form').addEventListener('submit',e=>{e.preventDefault();const hash=$('#torrent-hash').value.trim();if(hash)inspect(hash);else toast('Enter a torrent hash')});$('#move-search').addEventListener('input',renderQbitCatalog);$('#move-form').addEventListener('submit',e=>{e.preventDefault();const hash=$('#move-hash').value.trim();const target=$('#move-target').value;if(hash&&target)inspectMove(hash,target);else toast('Select a torrent and destination pool')});$('#global-hash').addEventListener('keydown',e=>{if(e.key==='Enter'&&e.target.value.trim())inspect(e.target.value)});$('#refresh').addEventListener('click',()=>{load();if(location.hash==='#move')loadQbitCatalog(true);toast('Refreshed')});$('#menu').addEventListener('click',()=>$('.sidebar').classList.toggle('open'));$('#sidebar-backdrop').addEventListener('click',()=>$('.sidebar').classList.remove('open'));navigate(location.hash.slice(1)||'sync');setSyncApp('radarr');bootstrap();
document.addEventListener('change',e=>{if(e.target.id==='select-all-auxiliary'){$$('.aux-file:not(:disabled)').forEach(input=>input.checked=e.target.checked);updateAuxiliarySelection()}else if(e.target.classList.contains('aux-file'))updateAuxiliarySelection()});
document.addEventListener('click',e=>{const details=e.target.closest('.inspect-operation');if(details){const operation=state.operations.find(item=>String(item.id)===details.dataset.operationId);if(operation){resetOperationSections();renderOperationDialog(operation);$('#operation-dialog').showModal()}}if(e.target.closest('#operation-done')||e.target.closest('#operation-close'))finishOperationTracking()});
$('#operation-dialog').addEventListener('cancel',e=>{if($('#operation-done').disabled)e.preventDefault();else finishOperationTracking()});
$('#connections-form').addEventListener('submit',saveConnections);
$('#runtime-form').addEventListener('submit',saveRuntime);
$('#revoke-sessions').addEventListener('click',revokeSessions);
document.addEventListener('click',event=>{const button=event.target.closest('.set-extra-action');if(button?.dataset.action==='move')$$('.move-extra-action').filter(input=>input.options[0].disabled).forEach(input=>input.value='delete')});
setInterval(refreshOperations,5000);
